Evaluate:

SELECT employee_id, salary, LAG(salary) OVER (ORDER BY employee_id) AS prev_salary
  FROM employees;

SELECT * FROM (
  SELECT department_id, job_id, salary FROM employees
)
PIVOT (
  SUM(salary)
  FOR job_id IN ('IT_PROG' AS it_prog, 'SA_REP' AS sa_rep, 'HR_REP' AS hr_rep)
);

